class RangeModule:

    def __init__(self):
        self.ranges = []

    def addRange(self, left: int, right: int) -> None:
        new_ranges = []
        i = 0
        n = len(self.ranges)
        while i < n and self.ranges[i][1] < left:
            new_ranges.append(self.ranges[i])
            i += 1
        while i < n and self.ranges[i][0] <= right:
            left = min(left, self.ranges[i][0])
            right = max(right, self.ranges[i][1])
            i += 1
        new_ranges.append((left, right))
        while i < n:
            new_ranges.append(self.ranges[i])
            i += 1
        self.ranges = new_ranges

    def queryRange(self, left: int, right: int) -> bool:
        l, r = 0, len(self.ranges) - 1
        while l <= r:
            mid = (l + r) // 2
            if self.ranges[mid][1] >= right:
                r = mid - 1
            else:
                l = mid + 1
        if l < len(self.ranges) and self.ranges[l][0] <= left and self.ranges[l][1] >= right:
            return True
        return False

    def removeRange(self, left: int, right: int) -> None:
        new_ranges = []
        for s, e in self.ranges:
            if e <= left or s >= right:
                new_ranges.append((s, e))
            else:
                if s < left:
                    new_ranges.append((s, left))
                if e > right:
                    new_ranges.append((right, e))
        self.ranges = new_ranges


# Your RangeModule object will be instantiated and called as such:
# obj = RangeModule()
# obj.addRange(left,right)
# param_2 = obj.queryRange(left,right)
# obj.removeRange(left,right)
```
efficiency: HIGH
time complexity: O(N) for addRange and removeRange, O(log N) for queryRange
space complexity: O(N)
energy implications: LOW
explanation: Maintain a sorted list of disjoint intervals. addRange merges overlapping/adjacent intervals in one linear pass. queryRange uses binary search to check if the query is fully covered by a single interval. removeRange splits or discards intervals intersecting the removal range. Efficient for up to 10^4 calls.

